insert into products (id, category_id, name, slug, short_description, description, specs_json, primary_image_url, gallery_urls_json, is_featured, is_active, created_at) values
('prod-4-cavity-rubber-moulding-die', 'cat-moulding-die', '4 Cavity Rubber Moulding Die', '4-cavity-rubber-moulding-die', 'Multi-cavity moulding die built for consistent cycle times and repeatable output.', 'Designed for industrial rubber part manufacturing, this 4 cavity rubber moulding die delivers accurate cavity balance, robust durability, and dependable production quality for repeated shop-floor use.', '{"Material":"Tool steel","Application":"Rubber moulding","Cavities":"4","Finish":"Precision machined"}'::jsonb, '/images/industrial-placeholder.svg', '["/images/industrial-placeholder.svg","/images/machining-placeholder.svg"]'::jsonb, true, true, now()),
('prod-plastic-blow-moulding-die', 'cat-moulding-die', 'Plastic Blow Moulding Die', 'plastic-blow-moulding-die', 'Custom blow moulding die for durable plastic product manufacturing.', 'A high-accuracy blow moulding die engineered for production consistency, dimensional control, and cleaner finish across industrial plastic components.', '{"Material":"Alloy steel / aluminium","Process":"Blow moulding","Industry":"Packaging and industrial plastics","Tolerance":"Application-specific"}'::jsonb, '/images/industrial-placeholder.svg', '["/images/industrial-placeholder.svg"]'::jsonb, false, true, now()),
('prod-plastic-bottle-moulding-die', 'cat-moulding-die', 'Plastic Bottle Moulding Die', 'plastic-bottle-moulding-die', 'Bottle moulding die optimized for repeatability and production throughput.', 'Precision-made bottle moulding die for plastic bottle applications requiring stable geometry, repeatable performance, and production-ready durability.', '{"Material":"Hardened steel","Product":"Bottle moulding","Output":"Production tooling","Surface":"Machined and polished"}'::jsonb, '/images/industrial-placeholder.svg', '["/images/industrial-placeholder.svg"]'::jsonb, false, true, now()),
('prod-aluminium-vacuum-forming-mould-die', 'cat-moulding-die', 'Aluminium Vacuum Forming Mould Die', 'aluminium-vacuum-forming-mould-die', 'Lightweight aluminium tooling for vacuum forming processes.', 'Built for vacuum forming applications, this aluminium mould die offers fast machining turnaround, good thermal behavior, and accurate part reproduction.', '{"Material":"Aluminium","Process":"Vacuum forming","Use":"Prototype and production","Finish":"Industrial polished"}'::jsonb, '/images/industrial-placeholder.svg', '["/images/industrial-placeholder.svg","/images/service-placeholder.svg"]'::jsonb, true, true, now()),
('prod-vmc-job-service', 'cat-cnc-components', 'VMC Job Service', 'vmc-job-service', 'Precision VMC job work support for custom industrial parts and batches.', 'Reliable VMC job service for components requiring repeatable machining quality, tight process control, and industry-ready turnaround times.', '{"Service":"VMC machining","Batch":"Prototype to medium production","Material":"MS, SS, aluminium, brass","Support":"Drawing-based manufacturing"}'::jsonb, '/images/machining-placeholder.svg', '["/images/machining-placeholder.svg","/images/service-placeholder.svg"]'::jsonb, true, true, now()),
('prod-stainless-steel-insert', 'cat-cnc-components', 'Stainless Steel Insert', 'stainless-steel-insert', 'Machined stainless steel insert for industrial assemblies and fixtures.', 'A precision stainless steel insert manufactured for fit-critical industrial applications where finish, consistency, and durability matter.', '{"Material":"Stainless steel","Finish":"Precision turned","Use":"Assemblies and fixtures","Tolerance":"Tight tolerance available"}'::jsonb, '/images/components-placeholder.svg', '["/images/components-placeholder.svg"]'::jsonb, false, true, now()),
('prod-cnc-components', 'cat-cnc-components', 'CNC Components', 'cnc-components', 'Custom CNC machined components for industrial and manufacturing buyers.', 'Versatile CNC components manufactured to client drawings with dependable dimensional accuracy and production-ready repeatability.', '{"Process":"CNC machining","Materials":"Steel, aluminium, brass, engineering plastics","Output":"Custom components","Quality":"Inspection-backed manufacturing"}'::jsonb, '/images/components-placeholder.svg', '["/images/components-placeholder.svg","/images/machining-placeholder.svg"]'::jsonb, true, true, now()),
('prod-cnc-turned-components', 'cat-cnc-components', 'CNC Turned Components', 'cnc-turned-components', 'Turned parts for industrial buyers needing repeatability and finish quality.', 'Production-friendly CNC turned components made for ongoing industrial use, tailored to dimensional needs and material selection.', '{"Process":"Turning","Use":"Industrial components","Batch":"Low to medium volume","Quality":"Controlled machining process"}'::jsonb, '/images/components-placeholder.svg', '["/images/components-placeholder.svg"]'::jsonb, true, true, now()),
('prod-brass-oilless-wear-plate', 'cat-wear-plates', 'Brass Oilless Wear Plate', 'brass-oilless-wear-plate', 'Durable brass wear plate designed for low-maintenance industrial movement.', 'Brass oilless wear plate solution designed for long life, reduced maintenance, and dependable load performance in industrial assemblies.', '{"Material":"Brass","Feature":"Oilless","Application":"Wear control","Industry":"Industrial machinery"}'::jsonb, '/images/components-placeholder.svg', '["/images/components-placeholder.svg"]'::jsonb, false, true, now()),
('prod-pneumatic-vehicle-cylinder', 'cat-engine-mounting', 'Pneumatic Vehicle Cylinder', 'pneumatic-vehicle-cylinder', 'Precision vehicle cylinder component for demanding industrial performance.', 'Custom-built pneumatic vehicle cylinder and mounting support component engineered for industrial durability and precision fitting.', '{"Material":"Application-specific alloy","System":"Pneumatic","Use":"Vehicle / industrial mounting","Build":"Custom machining support"}'::jsonb, '/images/service-placeholder.svg', '["/images/service-placeholder.svg"]'::jsonb, false, true, now()),
('prod-vmc-machine-services', 'cat-vmc-job-work', 'VMC Machine Services', 'vmc-machine-services', 'Precision VMC machine services for industrial fabrication and machining.', 'End-to-end VMC machine services with drawing-based machining support, repeatable production accuracy, and practical turnaround planning.', '{"Service":"VMC machine services","Materials":"MS, SS, aluminium, brass","Support":"Batch job work","Turnaround":"On request"}'::jsonb, '/images/machining-placeholder.svg', '["/images/machining-placeholder.svg"]'::jsonb, true, true, now()),
('prod-vmc-job-work', 'cat-vmc-job-work', 'VMC Job Work', 'vmc-job-work', 'Job work machining support for precise component manufacturing.', 'Flexible VMC job work service for industrial buyers who need custom machining based on part drawings, tolerances, and batch needs.', '{"Service":"Job work","Capacity":"Custom batches","Input":"2D / 3D drawing support","Focus":"Precision machining"}'::jsonb, '/images/machining-placeholder.svg', '["/images/machining-placeholder.svg"]'::jsonb, true, true, now()),
('prod-cnc-precision-components-job-work', 'cat-vmc-job-work', 'CNC Precision Components Job Work', 'cnc-precision-components-job-work', 'Precision job work for custom CNC components with controlled tolerances.', 'Built for industrial accuracy, this job work service supports precision component manufacturing across varied materials and production volumes.', '{"Service":"Precision job work","Process":"CNC / VMC","Output":"Custom components","IdealFor":"OEMs and industrial buyers"}'::jsonb, '/images/machining-placeholder.svg', '["/images/machining-placeholder.svg","/images/components-placeholder.svg"]'::jsonb, false, true, now()),
('prod-precision-machining-service', 'cat-vmc-job-work', 'Precision Machining Service', 'precision-machining-service', 'Custom precision machining service for demanding industrial requirements.', 'Ideal for buyers who need accurate machining, controlled delivery, and collaborative manufacturing support from enquiry to dispatch.', '{"Service":"Precision machining","Support":"Quote-based","Industry":"Industrial / OEM","Process":"Custom machining"}'::jsonb, '/images/service-placeholder.svg', '["/images/service-placeholder.svg","/images/machining-placeholder.svg"]'::jsonb, true, true, now()),
('prod-precision-vmc-machining-job-work', 'cat-cnc-machining-services', 'Precision VMC Machining Job Work', 'precision-vmc-machining-job-work', 'High-accuracy VMC machining job work for custom part production.', 'Precision VMC machining job work suitable for customers requiring process discipline, high-quality finish, and dependable delivery cycles.', '{"Process":"VMC machining","Service":"Job work","Material":"Application-based","Output":"Custom precision parts"}'::jsonb, '/images/machining-placeholder.svg', '["/images/machining-placeholder.svg"]'::jsonb, false, true, now()),
('prod-precision-machining-job-works', 'cat-cnc-machining-services', 'Precision Machining Job Works', 'precision-machining-job-works', 'Industrial machining job work for buyers needing production-ready accuracy.', 'A flexible machining service for industrial part requirements, from one-off development parts to repeatable batch job work.', '{"Service":"Machining job work","Volume":"Prototype to repeat production","Drawings":"Client-supplied drawings supported","Quality":"Inspection-based release"}'::jsonb, '/images/service-placeholder.svg', '["/images/service-placeholder.svg","/images/machining-placeholder.svg"]'::jsonb, false, true, now())
insert into site_content (id, page_key, section_key, title, body, meta_json, updated_at) values
('content-home-hero', 'home', 'hero', 'Precision manufacturing for industrial buyers who need dependable execution.', 'Mechnnovation Technologies manufactures moulding dies, CNC turned components, and VMC job work solutions from Narhe, Pune with a quote-first process built for OEMs, fabricators, and industrial procurement teams.', '{"eyebrow":"Mechnnovation Technologies","primaryCtaLabel":"Get Quote","secondaryCtaLabel":"View Products"}'::jsonb, now()),
('content-home-trust', 'home', 'trust', 'Trusted industrial capability with local execution strength.', '12+ years of experience, Pune-based manufacturing, GST registered since 2020, and a partnership-led business focused on dependable industrial delivery.', '{"cards":["12+ Years Experience","Pune-Based Manufacturing","GST Verified","Partnership Firm"]}'::jsonb, now()),
('content-home-process', 'home', 'process', 'How it works', 'A fast industrial buying flow designed around requirement clarity, engineering review, and quote turnaround.', '{"steps":["Browse","Submit Requirement","Get Quote","Order"]}'::jsonb, now()),
('content-home-why', 'home', 'why_choose_us', 'Why buyers choose Mechnnovation', 'We combine machining expertise, practical drawing support, and on-ground manufacturing response for industrial jobs where quality and delivery both matter.', '{"points":["Moulding die and precision job work capability","Responsive quote-driven workflow","Industrial material support across machining needs"]}'::jsonb, now()),
('content-about-story', 'about', 'story', 'Industrial manufacturing support built on 12+ years of hands-on execution.', 'Mechnnovation Technologies is a Pune-based partnership firm serving industrial buyers with moulding die manufacturing, VMC job work, CNC turned components, and custom machining support.', '{"stats":[{"label":"Years","value":"12+"},{"label":"Products","value":"100+"},{"label":"Location","value":"Pune"},{"label":"GST","value":"Verified"}]}'::jsonb, now()),
('content-about-capabilities', 'about', 'capabilities', 'Capabilities', 'CNC and VMC machining, moulding die development, drawing-based manufacturing, 2D/3D support, and industrial custom work.', '{"list":["CNC / VMC machining","Moulding die development","2D / 3D design support","Custom industrial manufacturing"]}'::jsonb, now()),
('content-contact-main', 'contact', 'main', 'Talk to the Mechnnovation team.', 'Share your machining, component, or tooling requirement and our team will review the scope and respond with the next steps.', '{"mapQuery":"Narhe Pune Rajlaxmi Industrial Estate"}'::jsonb, now())
